    if (!dateString) return 'TBD';
    return new Date(dateString).toLocaleDateString('en-US', { 
      month: 'long', day: 'numeric', year: 'numeric' 
    });
  };

  const safeGet = (val, fallback = '') => {
    if (Array.isArray(val)) return val[0] || fallback;
    return val || fallback;
  };

  const formatMultiLine = (text) => {
    if (!text) return '';
    return text.replace(/\n/g, '<br>');
  };

  const formatCurrency = (val) => {
    if (val === undefined || val === null || val === '') return '0';
    return `$${val}`;
  };

  // 3. PREPARE VARIABLES
  const requestDate = formatDate(data.candidateRequestDate);
  const expectedStartDate = formatDate(data.expectedStartDate);

  const requestor = safeGet(data.requestor, 'Unknown');
  const role = safeGet(data.roles, 'N/A');

  // --- NEW VARIABLES ---
  const fullTime = safeGet(data.fullTime, 'N/A'); 
  const requiredMVA = safeGet(data.requiredMVA, 'N/A');
  // ---------------------

  const jdLink = data.jdClientProfile || '#';

  // --- REPLACEMENT LOGIC ---
  const replacedMVA = safeGet(data.replacedMVA, '');
  const replacementReason = safeGet(data.replacementReason, '');
  const resignationWhy = data.resignationWhy || ''; // Long text field

  // CLIENT DETAILS
  const clientName = safeGet(data.clientName, 'TBD');
  const clientEmail = safeGet(data.clientEmail, '').trim();
  const rawClientPhone = safeGet(data.clientPhoneNumber, '');
  const clientPhone = (rawClientPhone && rawClientPhone !== 'None') ? rawClientPhone : '';

  const interviewer = clientName; 

  let contactDetails = '';
  if (clientEmail || clientPhone) {
    contactDetails = [clientEmail, clientPhone].filter(Boolean).join('<br>');
  } else {
    contactDetails = 'N/A';
  }

  const clientRate = formatCurrency(data.finalClientRate);
  const timezone = safeGet(data.timeZone, 'EST');
  const suf = formatCurrency(safeGet(data.suf, '0'));
  const company = safeGet(data.company, 'N/A');
  const address = safeGet(data.billingAddress, 'N/A');
  const summary = data.requestSummary || 'No summary provided.';

  const zoomLink = data.zoomLink || 'N/A';
  const onboarding = data.onboardingStrategy || 'N/A';

